+
+  for (const [id, record] of agentStates.entries()) {
+    if (isTerminalState(record.currentState)) {
+      const terminalDuration = now - record.stateEnteredAt.getTime();
+      if (terminalDuration > ttlMs) {
+        agentStates.delete(id);
+        cleaned++;
+      }
+    }
+  }
+
+  if (cleaned > 0) {
